 1→//! Function call code generation.
 2→
 3→use tc24r_ast::Expr;
 4→use tc24r_codegen_state::CodegenState;
 5→use tc24r_emit_macros::emit;
 6→
 7→/// Callback type for recursive expression generation.
 8→pub type GenExprFn = fn(&Expr, &mut CodegenState);
 9→
10→/// Generate a function call: push args right-to-left, jal, cleanup stack.
11→///
12→/// For `printf` and `sprintf` calls, dispatches to `__tc24r_printfN` where
13→/// N is the number of extra args (0-6), enabling freestanding printf without
14→/// true varargs support.
15→pub fn gen_call(state: &mut CodegenState, name: &str, args: &[Expr], gen_expr_fn: GenExprFn) {
16→    let call_name = if name == "printf" || name == "sprintf" {
17→        let extra = if args.is_empty() { 0 } else { args.len() - 1 };
18→        state.needs_printf = true;
19→        format!("___tc24r_printf{extra}")
20→    } else {
21→        format!("_{name}")
22→    };
23→
24→    for arg in args.iter().rev() {
25→        gen_expr_fn(arg, state);
26→        emit!(state, "        push    r0");
27→    }
28→    emit!(state, "        la      r0,{call_name}");
29→    emit!(state, "        jal     r1,(r0)");
30→    if !args.is_empty() {
31→        let cleanup = args.len() as i32 * 3;
32→        emit!(state, "        add     sp,{cleanup}");
33→    }
34→}
35→

150→        }
151→        if self.c_before != self.c_after {
152→            changes.push(format!("c:{}→{}", self.c_before as u8, self.c_after as u8));
153→        }
154→        if !changes.is_empty() {
155→            write!(f, "  [{}]", changes.join(" "))?;
156→        }
157→
158→        Ok(())
159→    }
160→}
