 1→//! Basic emit and label helpers.
 2→
 3→use tc24r_codegen_state::CodegenState;
 4→
 5→/// Append one line of assembly to the output buffer.
 6→pub fn emit(state: &mut CodegenState, line: &str) {
 7→    state.out.push_str(line);
 8→    state.out.push('\n');
 9→}
10→
11→/// Allocate a fresh unique label and return it.
12→pub fn new_label(state: &mut CodegenState) -> String {
13→    let label = format!("L{}", state.label_counter);
14→    state.label_counter += 1;
15→    label
16→}
17→
18→/// Emit a long branch-always: uses r2 for target to preserve r0.
19→pub fn emit_bra(state: &mut CodegenState, target: &str) {
20→    emit(state, &format!("        la      r2,{target}"));
21→    emit(state, "        jmp     (r2)");
22→}
23→
24→/// Emit a long branch-if-true: brf over la+jmp (no range limit).
25→/// Uses r2 for target address to preserve r0.
26→pub fn emit_brt(state: &mut CodegenState, target: &str) {
27→    let skip = new_label(state);
28→    emit(state, &format!("        brf     {skip}"));
29→    emit(state, &format!("        la      r2,{target}"));
30→    emit(state, "        jmp     (r2)");
31→    emit(state, &format!("{skip}:"));
32→}
33→
34→/// Emit a long branch-if-false: brt over la+jmp (no range limit).
35→/// Uses r2 for target address to preserve r0.
36→pub fn emit_brf(state: &mut CodegenState, target: &str) {
37→    let skip = new_label(state);
38→    emit(state, &format!("        brt     {skip}"));
39→    emit(state, &format!("        la      r2,{target}"));
40→    emit(state, "        jmp     (r2)");
41→    emit(state, &format!("{skip}:"));
42→}
