  1→//! COR24 instruction execution
  2→
  3→use super::instruction::{DecodedInstruction, InstructionFormat, Opcode};
  4→use super::state::{CpuState, DecodeRom, TraceEntry};
  5→
  6→/// Execute result
  7→#[derive(Debug, Clone, PartialEq, Eq)]
  8→pub enum ExecuteResult {
  9→    /// Instruction executed successfully
 10→    Ok,
 11→    /// CPU halted
 12→    Halted,
 13→    /// Invalid instruction
 14→    InvalidInstruction(u8),
 15→    /// Memory access error
 16→    MemoryError(u32),
 17→}
 18→
 19→/// COR24 instruction executor
 20→#[derive(Clone)]
 21→pub struct Executor {
 22→    decode_rom: DecodeRom,
 23→}
 24→
 25→impl Default for Executor {
 26→    fn default() -> Self {
 27→        Self::new()
 28→    }
 29→}
 30→
 31→impl Executor {
 32→    pub fn new() -> Self {
 33→        Self {
 34→            decode_rom: DecodeRom::new(),
 35→        }
 36→    }
 37→
 38→    /// Execute a single instruction
 39→    pub fn step(&self, cpu: &mut CpuState) -> ExecuteResult {
 40→        if cpu.halted {
 41→            return ExecuteResult::Halted;
 42→        }
 43→
 44→        // Check for pending interrupt at instruction boundary
 45→        // Hardware: automatic jal r7,(r6) when uart_rxrdy && ienab && !intis
 46→        if cpu.interrupt_pending() {
 47→            cpu.intis = true;
 48→            let target = cpu.get_reg(6); // r6 = interrupt vector
 49→            cpu.set_reg(7, cpu.pc); // r7 = return address (current PC)
 50→            cpu.pc = target;
 51→            cpu.cycles += 1;
 52→            cpu.instructions += 1;
 53→            return ExecuteResult::Ok;
 54→        }
 55→
 56→        // Fetch instruction byte
 57→        let inst_byte = cpu.read_byte(cpu.pc);
 58→
 59→        // Check for HALT (using 0x00 at address 0 as halt)
 60→        if inst_byte == 0x00 && cpu.pc == 0 {
 61→            cpu.halted = true;
 62→            return ExecuteResult::Halted;
 63→        }
 64→
 65→        // NOP: 0xFF is not in the decode ROM but is a valid no-op
 66→        if inst_byte == 0xFF {
 67→            cpu.pc = CpuState::mask_24(cpu.pc.wrapping_add(1));
 68→            cpu.instructions += 1;
 69→            return ExecuteResult::Ok;
 70→        }
 71→
 72→        // Decode instruction
 73→        let decoded_value = self.decode_rom.decode(inst_byte);
 74→        if decoded_value == 0xFFF {
 75→            return ExecuteResult::InvalidInstruction(inst_byte);
 76→        }
 77→
 78→        let inst = DecodedInstruction::from_decoded(decoded_value);
 79→        let format = inst.opcode.format();
 80→
 81→        // Fetch additional bytes based on format
 82→        let imm8 = match format {
 83→            InstructionFormat::TwoBytes | InstructionFormat::FourBytes => {
 84→                cpu.read_byte(cpu.pc.wrapping_add(1))
 85→            }
 86→            _ => 0,
 87→        };
 88→
 89→        let imm24 = match format {
 90→            InstructionFormat::FourBytes => {
 91→                let b0 = cpu.read_byte(cpu.pc.wrapping_add(1)) as u32;
 92→                let b1 = cpu.read_byte(cpu.pc.wrapping_add(2)) as u32;
 93→                let b2 = cpu.read_byte(cpu.pc.wrapping_add(3)) as u32;
 94→                b0 | (b1 << 8) | (b2 << 16)
 95→            }
 96→            _ => 0,
 97→        };
 98→
 99→        // Calculate next PC
100→        let inst_size: u32 = match format {
101→            InstructionFormat::SingleByte => 1,
102→            InstructionFormat::TwoBytes => 2,
103→            InstructionFormat::FourBytes => 4,
104→        };
105→        let next_pc = CpuState::mask_24(cpu.pc.wrapping_add(inst_size));
106→
107→        // Capture pre-execution state for trace
108→        let trace_pc = cpu.pc;
109→        let trace_regs_before = cpu.registers;
110→        let trace_c_before = cpu.c;
111→        let trace_sp_before = cpu.get_reg(4);
112→        let trace_instruction_num = cpu.instructions;
113→        let mut halted_by_self_branch = false;
114→
115→        // Execute instruction
116→        match inst.opcode {
117→            Opcode::AddReg => {
118→                // add ra,rb
119→                let ra_val = cpu.get_reg(inst.ra);
120→                let rb_val = cpu.get_reg(inst.rb);
121→                let result = CpuState::mask_24(ra_val.wrapping_add(rb_val));
122→                cpu.set_reg(inst.ra, result);
123→                cpu.pc = next_pc;
124→            }
125→
126→            Opcode::AddImm => {
127→                // add ra,dd
128→                let ra_val = cpu.get_reg(inst.ra);
129→                let imm = CpuState::sign_extend_8(imm8);
130→                let result = CpuState::mask_24(ra_val.wrapping_add(imm));
131→                cpu.set_reg(inst.ra, result);
132→                cpu.pc = next_pc;
133→            }
134→
135→            Opcode::And => {
136→                // and ra,rb
137→                let ra_val = cpu.get_reg(inst.ra);
138→                let rb_val = cpu.get_reg(inst.rb);
139→                cpu.set_reg(inst.ra, ra_val & rb_val);
140→                cpu.pc = next_pc;
141→            }
142→
143→            Opcode::Bra => {
144→                // bra dd (always branch)
145→                // Hardware pipeline: PC is 2 ahead of next instruction at execute time
146→                // So branch base = instruction_addr + 4 = next_pc + 2
147→                let offset = CpuState::sign_extend_8(imm8);
148→                let branch_base = next_pc.wrapping_add(2);
149→                let target = CpuState::mask_24(branch_base.wrapping_add(offset));
150→                // Detect self-branch (halt: bra halt) as halt condition
151→                let instruction_addr = CpuState::mask_24(next_pc.wrapping_sub(2));
152→                if target == instruction_addr {
153→                    cpu.pc = instruction_addr;
154→                    cpu.halted = true;
155→                    halted_by_self_branch = true;
156→                } else {
157→                    cpu.pc = target;
158→                }
159→            }
160→
161→            Opcode::Brf => {
162→                // brf dd (branch if false)
163→                if !cpu.c {
164→                    let offset = CpuState::sign_extend_8(imm8);
165→                    let branch_base = next_pc.wrapping_add(2);
166→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
167→                } else {
168→                    cpu.pc = next_pc;
169→                }
170→            }
171→
172→            Opcode::Brt => {
173→                // brt dd (branch if true)
174→                if cpu.c {
175→                    let offset = CpuState::sign_extend_8(imm8);
176→                    let branch_base = next_pc.wrapping_add(2);
177→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
178→                } else {
179→                    cpu.pc = next_pc;
180→                }
181→            }
182→
183→            Opcode::Ceq => {
184→                // ceq ra,rb (compare equal)
185→                let ra_val = cpu.get_reg(inst.ra);
186→                let rb_val = cpu.get_reg(inst.rb);
187→                cpu.c = ra_val == rb_val;
188→                cpu.pc = next_pc;
189→            }
190→
191→            Opcode::Cls => {
192→                // cls ra,rb (compare less signed)
193→                let ra_val = cpu.get_reg(inst.ra) as i32;
194→                let rb_val = cpu.get_reg(inst.rb) as i32;
195→                // Sign extend from 24-bit
196→                let ra_signed = if ra_val & 0x800000 != 0 {
197→                    ra_val | 0xFF000000u32 as i32
198→                } else {
199→                    ra_val
200→                };

  1→//! COR24 assembler
  2→//!
  3→//! Parses COR24 assembly language and produces machine code.
  4→//! Uses encoding tables extracted from the hardware decode ROM.
  5→
  6→use crate::cpu::encode;
  7→use crate::cpu::instruction::Opcode;
  8→use serde::{Deserialize, Serialize};
  9→use std::collections::HashMap;
 10→
 11→/// Assembly result
 12→#[derive(Debug, Clone, Serialize, Deserialize)]
 13→pub struct AssemblyResult {
 14→    pub bytes: Vec<u8>,
 15→    pub lines: Vec<AssembledLine>,
 16→    pub errors: Vec<String>,
 17→    pub labels: HashMap<String, u32>,
 18→}
