  1→//! Struct member access and assignment.
  2→
  3→use tc24r_ast::{Expr, Type};
  4→use tc24r_codegen_state::CodegenState;
  5→use tc24r_emit_core::load_immediate;
  6→use tc24r_emit_macros::emit;
  7→
  8→/// Callback type for recursive expression generation.
  9→pub type GenExprFn = fn(&Expr, &mut CodegenState);
 10→
 11→/// Load struct member `object.member` into r0.
 12→pub fn gen_member_access(
 13→    state: &mut CodegenState,
 14→    object: &Expr,
 15→    member: &str,
 16→    gen_expr_fn: GenExprFn,
 17→) {
 18→    let (mem_offset, is_char) = member_info(state, object, member);
 19→    emit_member_addr(state, object, mem_offset, gen_expr_fn);
 20→    if is_char {
 21→        emit!(state, "        lbu     r0,0(r0)");
 22→    } else {
 23→        emit!(state, "        lw      r0,0(r0)");
 24→    }
 25→}
 26→
 27→/// Store value into struct member `object.member`.
 28→pub fn gen_member_assign(
 29→    state: &mut CodegenState,
 30→    object: &Expr,
 31→    member: &str,
 32→    value: &Expr,
 33→    gen_expr_fn: GenExprFn,
 34→) {
 35→    let (mem_offset, is_char) = member_info(state, object, member);
 36→    gen_expr_fn(value, state);
 37→    emit!(state, "        push    r0");
 38→    emit_member_addr(state, object, mem_offset, gen_expr_fn);
 39→    emit!(state, "        mov     r1,r0");
 40→    emit!(state, "        pop     r0");
 41→    if is_char {
 42→        emit!(state, "        sb      r0,0(r1)");
 43→    } else {
 44→        emit!(state, "        sw      r0,0(r1)");
 45→    }
 46→}
 47→
 48→/// Emit code to compute member address into r0.
 49→fn emit_member_addr(
 50→    state: &mut CodegenState,
 51→    object: &Expr,
 52→    mem_offset: i32,
 53→    gen_expr_fn: GenExprFn,
 54→) {
 55→    match object {
 56→        Expr::Ident(name) => {
 57→            // Local struct: fp + var_offset + member_offset
 58→            let fp_offset = state.locals[name.as_str()];
 59→            load_immediate(state, fp_offset + mem_offset);
 60→            emit!(state, "        add     r0,fp");
 61→        }
 62→        Expr::Deref(ptr) => {
 63→            // Pointer to struct: evaluate ptr, add member_offset
 64→            gen_expr_fn(ptr, state);
 65→            if mem_offset != 0 {
 66→                emit!(state, "        push    r0");
 67→                load_immediate(state, mem_offset);
 68→                emit!(state, "        pop     r1");
 69→                emit!(state, "        add     r0,r1");
 70→            }
 71→        }
 72→        _ => {
 73→            // General case: evaluate object as address, add offset
 74→            gen_expr_fn(object, state);
 75→            if mem_offset != 0 {
 76→                emit!(state, "        push    r0");
 77→                load_immediate(state, mem_offset);
 78→                emit!(state, "        pop     r1");
 79→                emit!(state, "        add     r0,r1");
 80→            }
 81→        }
 82→    }
 83→}
 84→
 85→/// Get member offset and whether it's a char type.
 86→fn member_info(state: &CodegenState, object: &Expr, member: &str) -> (i32, bool) {
 87→    let ty = object_type(state, object);
 88→    let m = ty.find_member(member).unwrap_or_else(|| {
 89→        panic!("unknown struct member '{member}' in type {ty:?}")
 90→    });
 91→    (m.offset, m.ty == Type::Char)
 92→}
 93→
 94→/// Determine the struct type of the object expression.
 95→/// Walks the expression tree to resolve nested member accesses.
 96→fn object_type(state: &CodegenState, object: &Expr) -> Type {
 97→    let ty = match object {
 98→        Expr::Ident(name) => {
 99→            if let Some(ty) = state.local_types.get(name.as_str()) {
100→                ty.clone()
101→            } else if let Some(ty) = state.global_types.get(name.as_str()) {
102→                ty.clone()
103→            } else {
104→                Type::Int
105→            }
106→        }
107→        Expr::Deref(ptr) => {
108→            let ptr_ty = object_type(state, ptr);
109→            match ptr_ty {
110→                Type::Ptr(inner) => *inner,
111→                _ => ptr_ty,
112→            }
113→        }
114→        Expr::Call { name, .. } => {
115→            if let Some(ty) = state.function_types.get(name.as_str()) {
116→                ty.clone()
117→            } else {
118→                Type::Int
119→            }
120→        }
121→        Expr::MemberAccess { object: obj, member } => {
122→            let struct_ty = object_type(state, obj);
123→            if let Some(m) = struct_ty.find_member(member) {
124→                m.ty.clone()
125→            } else {
126→                Type::Int
127→            }
128→        }
129→        _ => Type::Int,
130→    };
131→    // Resolve incomplete struct placeholders via the struct registry
132→    resolve_struct(state, ty)
133→}
134→
135→/// If a struct type is an empty placeholder (forward-declared),
136→/// look up the full definition from the struct registry.
137→fn resolve_struct(state: &CodegenState, ty: Type) -> Type {
138→    match &ty {
139→        Type::Struct { tag: Some(name), members, .. } if members.is_empty() => {
140→            if let Some(full) = state.struct_types.get(name) {
141→                full.clone()
142→            } else {
143→                ty
144→            }
145→        }
146→        Type::Ptr(inner) => Type::Ptr(Box::new(resolve_struct(state, *inner.clone()))),
147→        _ => ty,
148→    }
149→}
