 1→//! C type representations.
 2→
 3→/// A C type.
 4→#[derive(Debug, Clone, PartialEq)]
 5→pub enum Type {
 6→    Char,
 7→    Int,
 8→    Void,
 9→    Ptr(Box<Type>),
10→    /// Fixed-size array: element type and count.
11→    Array(Box<Type>, usize),
12→    /// Struct type with optional tag name and members.
13→    Struct {
14→        tag: Option<String>,
15→        members: Vec<StructMember>,
16→        total_size: i32,
17→    },
18→}
19→
20→/// A struct member with name, type, and byte offset from struct base.
21→#[derive(Debug, Clone, PartialEq)]
22→pub struct StructMember {
23→    pub name: String,
24→    pub ty: Type,
25→    pub offset: i32,
26→}
27→
28→impl Type {
29→    /// Size in bytes for this type.
30→    pub fn size(&self) -> i32 {
31→        match self {
32→            Type::Char => 1,
33→            Type::Int | Type::Void | Type::Ptr(_) => 3,
34→            Type::Array(elem, count) => elem.size() * (*count as i32),
35→            Type::Struct { total_size, .. } => *total_size,
36→        }
37→    }
38→
39→    /// Element type for arrays and pointers.
40→    pub fn element_type(&self) -> Option<&Type> {
41→        match self {
42→            Type::Ptr(inner) | Type::Array(inner, _) => Some(inner),
43→            _ => None,
44→        }
45→    }
46→
47→    /// Look up a struct member by name.
48→    pub fn find_member(&self, name: &str) -> Option<&StructMember> {
49→        match self {
50→            Type::Struct { members, .. } => members.iter().find(|m| m.name == name),
51→            _ => None,
52→        }
53→    }
54→}
