 1→//! Variable load with array decay.
 2→
 3→use tc24r_ast::Type;
 4→use tc24r_codegen_state::CodegenState;
 5→use tc24r_emit_load_store::{gen_addr_of, gen_load_by_name};
 6→use tc24r_emit_macros::emit;
 7→
 8→/// Load a variable into r0. Arrays decay to a pointer (address of first element).
 9→pub fn gen_ident(state: &mut CodegenState, name: &str) {
10→    if let Some(Type::Array(..)) = state.local_types.get(name) {
11→        gen_addr_of(state, name);
12→        return;
13→    }
14→    if state.globals.contains(name) {
15→        let is_char = state.global_types.get(name) == Some(&Type::Char);
16→        emit!(state, "        la      r1,_{name}");
17→        if is_char {
18→            emit!(state, "        lbu     r0,0(r1)");
19→        } else {
20→            emit!(state, "        lw      r0,0(r1)");
21→        }
22→    } else {
23→        gen_load_by_name(state, name);
24→    }
25→}
