  1→//! cor24-dbg: GDB-like CLI debugger for the MakerLisp COR24 processor
  2→//!
  3→//! Usage:
  4→//!   cor24-dbg <file.lgo>           Load an LGO file and start debugging
  5→//!   cor24-dbg --entry 0x93 <file>  Set entry point address
  6→
  7→use cor24_emulator::emulator::{EmulatorCore, StopReason};
  8→use std::io::{self, BufRead, Write};
  9→
 10→fn main() {
 11→    let args: Vec<String> = std::env::args().collect();
 12→    if args.len() < 2 {
 13→        eprintln!("cor24-dbg: MakerLisp COR24 debugger\n");
 14→        eprintln!("Usage:");
 15→        eprintln!("  cor24-dbg <file.lgo>                Load LGO file");
 16→        eprintln!("  cor24-dbg --entry <addr> <file.lgo>  Set entry point");
 17→        eprintln!("\nCommands: run, step, break, info, examine, disas, reset, quit");
 18→        std::process::exit(1);
 19→    }
 20→
 21→    let mut entry_override: Option<u32> = None;
 22→    let mut filename = None;
 23→
 24→    let mut i = 1;
 25→    while i < args.len() {
 26→        match args[i].as_str() {
 27→            "--entry" | "-e" => {
 28→                i += 1;
 29→                if i < args.len() {
 30→                    entry_override = Some(parse_addr(&args[i]).unwrap_or_else(|| {
 31→                        eprintln!("Bad address: {}", args[i]);
 32→                        std::process::exit(1);
 33→                    }));
 34→                }
 35→            }
 36→            _ => {
 37→                filename = Some(args[i].clone());
 38→            }
 39→        }
 40→        i += 1;
 41→    }
 42→
 43→    let filename = filename.unwrap_or_else(|| {
 44→        eprintln!("No file specified");
 45→        std::process::exit(1);
 46→    });
 47→
 48→    let mut dbg = Debugger::new();
 49→
 50→    if let Err(e) = dbg.load_file(&filename, entry_override) {
 51→        eprintln!("Error loading {}: {}", filename, e);
 52→        std::process::exit(1);
 53→    }
 54→
 55→    dbg.repl();
 56→}
 57→
 58→struct Debugger {
 59→    emu: EmulatorCore,
 60→    loaded: bool,
 61→    /// Track UART output position for incremental printing
 62→    uart_printed: usize,
 63→}
 64→
 65→impl Debugger {
 66→    fn new() -> Self {
 67→        Self {
 68→            emu: EmulatorCore::new(),
 69→            loaded: false,
 70→            uart_printed: 0,
 71→        }
 72→    }
 73→
 74→    fn load_file(&mut self, path: &str, entry: Option<u32>) -> Result<(), String> {
 75→        let content = std::fs::read_to_string(path)
 76→            .map_err(|e| format!("Cannot read file: {}", e))?;
 77→
 78→        let bytes = self.emu.load_lgo(&content, entry)?;
 79→        self.loaded = true;
 80→        self.uart_printed = 0;
 81→
 82→        println!("Loaded {} bytes from {}", bytes, path);
 83→        println!("PC = 0x{:06X}", self.emu.pc());
 84→        Ok(())
 85→    }
 86→
 87→    fn repl(&mut self) {
 88→        let stdin = io::stdin();
 89→        let mut last_cmd = String::new();
 90→
 91→        loop {
 92→            print!("(cor24) ");
 93→            io::stdout().flush().ok();
 94→
 95→            let mut line = String::new();
 96→            if stdin.lock().read_line(&mut line).unwrap_or(0) == 0 {
 97→                println!();
 98→                break;
 99→            }
100→            let line = line.trim().to_string();
101→
102→            let cmd = if line.is_empty() {
103→                last_cmd.clone()
104→            } else {
105→                last_cmd = line.clone();
106→                line
107→            };
108→
109→            if cmd.is_empty() {
110→                continue;
111→            }
112→
113→            let parts: Vec<&str> = cmd.splitn(2, ' ').collect();
114→            let arg = if parts.len() > 1 { parts[1].trim() } else { "" };
115→
116→            match parts[0] {
117→                "q" | "quit" | "exit" => break,
118→                "r" | "run" => self.cmd_run(arg),
119→                "s" | "step" | "si" => self.cmd_step(arg),
120→                "n" | "next" => self.cmd_next(),
121→                "c" | "cont" | "continue" => self.cmd_continue(),
122→                "b" | "break" => self.cmd_break(arg),
123→                "d" | "delete" => self.cmd_delete(arg),
124→                "i" | "info" => self.cmd_info(arg),
125→                "x" | "examine" => self.cmd_examine(arg),
126→                "p" | "print" => self.cmd_print(arg),
127→                "disas" | "disassemble" => self.cmd_disas(arg),
128→                "load" => {
129→                    if arg.is_empty() {
130→                        println!("Usage: load <file.lgo>");
131→                    } else if let Err(e) = self.load_file(arg, None) {
132→                        println!("Error: {}", e);
133→                    }
134→                }
135→                "reset" => {
136→                    self.emu.reset();
137→                    self.uart_printed = 0;
138→                    println!("CPU reset. PC = 0x{:06X}", self.emu.pc());
139→                }
140→                "t" | "trace" => self.cmd_trace(arg),
141→                "uart" => self.cmd_uart(arg),
142→                "led" => self.cmd_led(),
143→                "button" | "btn" => self.cmd_button(arg),
144→                "help" | "h" | "?" => self.cmd_help(),
145→                _ => println!("Unknown command: '{}'. Type 'help' for commands.", parts[0]),
146→            }
147→        }
148→    }
149→
150→    fn print_new_uart(&mut self) {
151→        let output = self.emu.get_uart_output();
152→        if output.len() > self.uart_printed {
153→            print!("{}", &output[self.uart_printed..]);
154→            io::stdout().flush().ok();
155→            self.uart_printed = output.len();
156→        }
157→    }
158→
159→    fn cmd_run(&mut self, arg: &str) {
160→        if self.emu.is_halted() {
161→            println!("CPU is halted. Use 'reset' to restart.");
162→            return;
163→        }
164→
165→        let max: u64 = if arg.is_empty() {
166→            100_000_000
167→        } else {
168→            arg.replace('_', "").parse().unwrap_or(100_000_000)
169→        };
170→
171→        self.emu.resume();
172→        let result = self.emu.run_batch(max);
173→        self.print_new_uart();
174→
175→        match result.reason {
176→            StopReason::Halted => {
177→                println!("\nCPU halted after {} instructions", result.instructions_run);
178→                self.cmd_trace("10");
179→            }
180→            StopReason::Breakpoint(addr) => {
181→                println!("Breakpoint at 0x{:06X}", addr);
182→            }
183→            StopReason::InvalidInstruction(byte) => {
184→                println!("\nInvalid instruction 0x{:02X} after {} instructions",
185→                    byte, result.instructions_run);
186→            }
187→            StopReason::CycleLimit => {
188→                println!("\nStopped after {} instructions (limit). PC = 0x{:06X}",
189→                    result.instructions_run, self.emu.pc());
190→            }
191→            StopReason::Paused => {}
192→        }
193→
194→        self.show_location();
195→    }
196→
197→    fn cmd_step(&mut self, arg: &str) {
198→        let n: u64 = if arg.is_empty() { 1 } else { arg.parse().unwrap_or(1) };
199→
200→        for _ in 0..n {

  1→//! LGO file loader for COR24
  2→//!
  3→//! Parses the monitor "load and go" format produced by `as24 | longlgo`.
  4→//!
  5→//! Format:
  6→//!   `L<AAAAAA><HH><HH>...`   Load hex bytes at 24-bit address
  7→//!   `G<AAAAAA>`               Go — set PC to address (optional)
  8→//!
  9→//! The address is 6 hex digits. Data bytes follow as pairs of hex digits.
 10→
 11→use crate::cpu::state::CpuState;
 12→
 13→/// Result of loading an LGO file
 14→pub struct LoadResult {
 15→    /// Start address from G line, if present
 16→    pub start_addr: Option<u32>,
 17→    /// Total bytes loaded
 18→    pub bytes_loaded: usize,
 19→    /// Highest address written (end of code+data region)
 20→    pub highest_address: u32,
 21→}
 22→
 23→/// Parse a single LGO L-line, returning (address, bytes)
 24→pub fn parse_lgo_load_line(line: &str) -> Result<(u32, Vec<u8>), String> {
 25→    let line = line.trim();
 26→    if !line.starts_with('L') || line.len() < 7 {
 27→        return Err(format!("Not a valid L line: '{}'", line));
 28→    }
 29→
 30→    let addr_str = &line[1..7];
 31→    let addr = u32::from_str_radix(addr_str, 16)
 32→        .map_err(|e| format!("Bad address '{}': {}", addr_str, e))?;
 33→
 34→    let data_str = &line[7..];
 35→    if !data_str.len().is_multiple_of(2) {
 36→        return Err(format!("Odd number of hex digits in data: '{}'", data_str));
 37→    }
 38→
 39→    let mut bytes = Vec::with_capacity(data_str.len() / 2);
 40→    for i in (0..data_str.len()).step_by(2) {
 41→        let byte = u8::from_str_radix(&data_str[i..i + 2], 16)
 42→            .map_err(|e| format!("Bad hex byte '{}': {}", &data_str[i..i + 2], e))?;
 43→        bytes.push(byte);
 44→    }
 45→
 46→    Ok((addr, bytes))
 47→}
 48→
 49→/// Parse a G-line, returning the start address
 50→pub fn parse_lgo_go_line(line: &str) -> Result<u32, String> {
 51→    let line = line.trim();
 52→    if !line.starts_with('G') || line.len() < 7 {
 53→        return Err(format!("Not a valid G line: '{}'", line));
 54→    }
 55→
 56→    let addr_str = &line[1..7];
 57→    u32::from_str_radix(addr_str, 16)
 58→        .map_err(|e| format!("Bad address '{}': {}", addr_str, e))
 59→}
 60→
 61→/// Load an LGO file into CPU memory
 62→pub fn load_lgo(content: &str, cpu: &mut CpuState) -> Result<LoadResult, String> {
 63→    let mut start_addr = None;
 64→    let mut bytes_loaded = 0usize;
 65→    let mut highest_address = 0u32;
 66→
 67→    for (line_num, line) in content.lines().enumerate() {
 68→        let line = line.trim();
 69→        if line.is_empty() {
 70→            continue;
 71→        }
 72→
 73→        match line.chars().next() {
 74→            Some('L') => {
 75→                let (addr, bytes) = parse_lgo_load_line(line)
 76→                    .map_err(|e| format!("Line {}: {}", line_num + 1, e))?;
 77→                for (i, &byte) in bytes.iter().enumerate() {
 78→                    cpu.write_byte(addr + i as u32, byte);
 79→                }
 80→                let end = addr + bytes.len() as u32;
 81→                if end > highest_address {
 82→                    highest_address = end;
 83→                }
 84→                bytes_loaded += bytes.len();
 85→            }
 86→            Some('G') => {
 87→                start_addr = Some(
 88→                    parse_lgo_go_line(line)
 89→                        .map_err(|e| format!("Line {}: {}", line_num + 1, e))?,
 90→                );
 91→            }
 92→            Some(';') | Some('#') => {
 93→                // Comment line, skip
 94→            }
 95→            _ => {
 96→                return Err(format!("Line {}: Unknown line type: '{}'", line_num + 1, line));
 97→            }
 98→        }
 99→    }
100→
101→    Ok(LoadResult {
102→        start_addr,
103→        bytes_loaded,
104→        highest_address,
105→    })
106→}
107→
