  2→
  3→use tc24r_ast::{BinOp, Expr, Type};
  4→use tc24r_codegen_state::CodegenState;
  5→use tc24r_emit_core::load_immediate;
  6→use tc24r_emit_macros::emit;
  7→use tc24r_type_infer::{GenExprFn, expr_type, gen_simple_into_r1, is_simple_expr};
  8→
  9→/// Generate add or subtract, dispatching to the appropriate variant.
 10→pub fn gen_add_sub(
 11→    state: &mut CodegenState,
 12→    op: BinOp,
 13→    lhs: &Expr,
 14→    rhs: &Expr,
 15→    gen_expr_fn: GenExprFn,
 16→) {
 17→    let lhs_ty = expr_type(state, lhs);
 18→    let rhs_ty = expr_type(state, rhs);
 19→    let lhs_is_ptr = matches!(&lhs_ty, Some(Type::Ptr(_)));
 20→    let rhs_is_ptr = matches!(&rhs_ty, Some(Type::Ptr(_)));
 21→
 22→    if op == BinOp::Sub && lhs_is_ptr && rhs_is_ptr {
 23→        gen_ptr_diff(state, lhs, rhs, &lhs_ty, gen_expr_fn);
 24→    } else if lhs_is_ptr {
 25→        gen_ptr_offset(state, op, lhs, rhs, &lhs_ty, gen_expr_fn);
 26→    } else {
 27→        gen_plain_add_sub(state, op, lhs, rhs, gen_expr_fn);
 28→    }
 29→}
 30→
 31→/// ptr - ptr: subtract addresses, divide by element size.
 32→fn gen_ptr_diff(
 33→    state: &mut CodegenState,
 34→    lhs: &Expr,
 35→    rhs: &Expr,
 36→    lhs_ty: &Option<Type>,
 37→    gen_expr_fn: GenExprFn,
 38→) {
 39→    let elem_size = match lhs_ty {
 40→        Some(Type::Ptr(inner)) => inner.size(),
 41→        _ => 1,
 42→    };
 43→    if is_simple_expr(rhs, state) {
 44→        gen_expr_fn(lhs, state);
 45→        gen_simple_into_r1(rhs, state);
 46→    } else {
 47→        gen_expr_fn(lhs, state);
 48→        emit!(state, "        push    r0");
 49→        gen_expr_fn(rhs, state);
 50→        emit!(state, "        mov     r1,r0");
 51→        emit!(state, "        pop     r0");
 52→    }
 53→    emit!(state, "        sub     r0,r1");
 54→    if elem_size > 1 {
 55→        emit_div_by_size(state, elem_size);
 56→    }
 57→}
 58→
 59→/// Emit a division by a constant element size for ptr-ptr diff.
 60→fn emit_div_by_size(state: &mut CodegenState, elem_size: i32) {
 61→    state.needs_div = true;
 62→    emit!(state, "        push    r0");
 63→    load_immediate(state, elem_size);
 64→    emit!(state, "        push    r0");
 65→    emit!(state, "        pop     r1");
 66→    emit!(state, "        pop     r0");
 67→    emit!(state, "        push    r1");
 68→    emit!(state, "        push    r0");
 69→    emit!(state, "        la      r0,__tc24r_div");
 70→    emit!(state, "        jal     r1,(r0)");
 71→    emit!(state, "        add     sp,6");
 72→}
 73→
 74→/// ptr +/- int: scale the integer by the pointee element size.
 75→fn gen_ptr_offset(
 76→    state: &mut CodegenState,
 77→    op: BinOp,
 78→    lhs: &Expr,
 79→    rhs: &Expr,
 80→    lhs_ty: &Option<Type>,
 81→    gen_expr_fn: GenExprFn,
 82→) {
 83→    let scale = match lhs_ty {
 84→        Some(Type::Ptr(inner)) => inner.size(),
 85→        _ => 1,
 86→    };
 87→    // When rhs is simple AND no scaling needed, skip push/pop entirely.
 88→    // When scaling is needed, we must use r0 for the multiply, so push/pop.
 89→    if is_simple_expr(rhs, state) && scale <= 1 {
 90→        gen_expr_fn(lhs, state);
 91→        gen_simple_into_r1(rhs, state);
 92→    } else {
 93→        gen_expr_fn(lhs, state);
 94→        emit!(state, "        push    r0");
 95→        gen_expr_fn(rhs, state);
 96→        if scale > 1 {
 97→            emit!(state, "        lc      r1,{scale}");
 98→            emit!(state, "        mul     r0,r1");
 99→        }
100→        emit!(state, "        mov     r1,r0");
101→        emit!(state, "        pop     r0");
102→    }
103→    emit_add_or_sub(state, op);
104→}
105→
106→/// Plain int +/- int with no scaling.
107→fn gen_plain_add_sub(
108→    state: &mut CodegenState,
109→    op: BinOp,
110→    lhs: &Expr,
111→    rhs: &Expr,
112→    gen_expr_fn: GenExprFn,
113→) {
114→    if is_simple_expr(rhs, state) {
115→        gen_expr_fn(lhs, state);
116→        gen_simple_into_r1(rhs, state);
117→    } else {
118→        gen_expr_fn(lhs, state);
119→        emit!(state, "        push    r0");
120→        gen_expr_fn(rhs, state);
121→        emit!(state, "        mov     r1,r0");
122→        emit!(state, "        pop     r0");
123→    }
124→    emit_add_or_sub(state, op);
125→}
126→
127→/// Emit the final add or sub instruction.
128→fn emit_add_or_sub(state: &mut CodegenState, op: BinOp) {
129→    match op {
130→        BinOp::Add => {
131→            emit!(state, "        add     r0,r1");
132→        }
133→        BinOp::Sub => {
134→            emit!(state, "        sub     r0,r1");
135→        }
136→        _ => unreachable!(),
137→    }
138→}
139→
140→/// Generate multiply. Assumes r0=lhs, r1=rhs already evaluated.
141→pub fn gen_mul(state: &mut CodegenState) {
142→    emit!(state, "        mul     r0,r1");
143→}
