 1→//! Data section emission.
 2→
 3→use tc24r_ast::{Expr, Program, Type};
 4→use tc24r_codegen_state::CodegenState;
 5→use tc24r_emit_macros::emit;
 6→
 7→/// Emit the `.data` section for globals and string literals.
 8→pub fn emit_data_section(state: &mut CodegenState, program: &Program) {
 9→    let has_globals = !program.globals.is_empty();
10→    let has_strings = !state.string_literals.is_empty();
11→    if !has_globals && !has_strings {
12→        return;
13→    }
14→    emit!(state, "");
15→    emit!(state, "        .data");
16→    for g in &program.globals {
17→        let name = &g.name;
18→        emit!(state, "_{name}:");
19→        let val = match &g.init {
20→            Some(Expr::IntLit(v)) => *v,
21→            _ => 0,
22→        };
23→        if g.ty == Type::Char {
24→            emit!(state, "        .byte   {val}");
25→        } else {
26→            emit!(state, "        .word   {val}");
27→        }
28→    }
29→    for (i, s) in state.string_literals.clone().iter().enumerate() {
30→        emit!(state, "_S{i}:");
31→        let bytes: Vec<String> = s
32→            .bytes()
33→            .chain(std::iter::once(0))
34→            .map(|b| b.to_string())
35→            .collect();
36→        let byte_str = bytes.join(",");
37→        emit!(state, "        .byte   {byte_str}");
38→    }
39→}
40→

 1→//! Division and modulo via runtime helper calls.
 2→//!
 3→//! The COR24 ISA has no hardware divide, so div/mod are implemented as
 4→//! runtime subroutines using repeated subtraction.
 5→
 6→use tc24r_codegen_state::CodegenState;
 7→use tc24r_emit_macros::emit;
 8→
 9→/// Emit a call to a div/mod runtime helper.
10→/// Assumes r0=lhs (dividend), r1=rhs (divisor) already evaluated.
11→///
12→/// Pass `is_mod: false` for division, `true` for modulo.
13→pub fn gen_divmod_call(state: &mut CodegenState, is_mod: bool) {
14→    let label = if is_mod {
15→        state.needs_mod = true;
16→        "__tc24r_mod"
17→    } else {
18→        state.needs_div = true;
19→        "__tc24r_div"
20→    };
21→    emit!(state, "        push    r1");
22→    emit!(state, "        push    r0");
23→    emit!(state, "        la      r0,{label}");
24→    emit!(state, "        jal     r1,(r0)");
25→    emit!(state, "        add     sp,6");
26→}
27→
28→/// Emit runtime subroutines if needed. Call at end of code generation.
29→pub fn emit_divmod_runtime(state: &mut CodegenState) {
30→    if !state.needs_div && !state.needs_mod {
31→        return;
32→    }
33→    state.out.push('\n');
34→    if state.needs_div {
35→        emit_div_routine(state);
36→    }
37→    if state.needs_mod {
38→        emit_mod_routine(state);
39→    }
40→}
41→
42→/// Emit the __tc24r_div subroutine (repeated subtraction, returns quotient).
43→fn emit_div_routine(state: &mut CodegenState) {
44→    emit!(state, "__tc24r_div:");
45→    emit!(state, "        push    fp");
46→    emit!(state, "        push    r2");
47→    emit!(state, "        push    r1");
48→    emit!(state, "        mov     fp,sp");
49→    emit!(state, "        lw      r0,9(fp)");
50→    emit!(state, "        lw      r1,12(fp)");
51→    emit!(state, "        lc      r2,0");
52→    emit!(state, "__tc24r_div_lp:");
53→    emit!(state, "        cls     r0,r1");
54→    emit!(state, "        brt     __tc24r_div_dn");
55→    emit!(state, "        sub     r0,r1");
56→    emit!(state, "        add     r2,1");
57→    emit!(state, "        bra     __tc24r_div_lp");
58→    emit_runtime_epilogue(state, "__tc24r_div_dn", true);
59→}
60→
61→/// Emit the __tc24r_mod subroutine (repeated subtraction, returns remainder).
62→fn emit_mod_routine(state: &mut CodegenState) {
63→    emit!(state, "__tc24r_mod:");
64→    emit!(state, "        push    fp");
65→    emit!(state, "        push    r2");
66→    emit!(state, "        push    r1");
67→    emit!(state, "        mov     fp,sp");
68→    emit!(state, "        lw      r0,9(fp)");
69→    emit!(state, "        lw      r1,12(fp)");
70→    emit!(state, "__tc24r_mod_lp:");
71→    emit!(state, "        cls     r0,r1");
72→    emit!(state, "        brt     __tc24r_mod_dn");
73→    emit!(state, "        sub     r0,r1");
74→    emit!(state, "        bra     __tc24r_mod_lp");
75→    emit_runtime_epilogue(state, "__tc24r_mod_dn", false);
76→}
77→
78→/// Shared epilogue for div/mod: label, optional mov r0,r2, standard return.
79→fn emit_runtime_epilogue(state: &mut CodegenState, done_label: &str, is_div: bool) {
80→    emit!(state, "{done_label}:");
81→    if is_div {
82→        emit!(state, "        mov     r0,r2");
83→    }
84→    emit!(state, "        mov     sp,fp");
85→    emit!(state, "        pop     r1");
86→    emit!(state, "        pop     r2");
87→    emit!(state, "        pop     fp");
88→    emit!(state, "        jmp     (r1)");
89→}
90→

 1→//! ISR prologue: save all registers and condition flag.
 2→
 3→use tc24r_codegen_state::CodegenState;
 4→use tc24r_emit_macros::emit_lines;
 5→use tc24r_struct_prologue::emit_locals_alloc;
 6→
 7→/// Emit ISR prologue: push r0/r1/r2, save condition flag, set frame pointer,
 8→/// allocate locals.
 9→pub fn emit_isr_prologue(state: &mut CodegenState) {
10→    emit_lines!(
11→        state,
12→        "        push    r0",
13→        "        push    r1",
14→        "        push    r2",
15→        "        mov     r2,c",
16→        "        push    r2",
17→        "        push    fp",
18→        "        mov     fp,sp",
19→    );
20→    emit_locals_alloc(state);
21→}
